mapper.select:
SELECT s.id, s.projectCode AS presalesCode, s.serialNumber, s.productCode, s.productName, s.productModel, s.quantity, s.shipmentState, s.createTime FROM pm_shipment_info s WHERE s.projectCode = #{presalesCode}
AND s.shipmentState != 'RMA'
ORDER BY s.createTime DESC

SELECT ta.id, ta.lendInfoId, ta.authCode, ta.authType, ta.startTime, ta.endTime, ta.status, ta.createTime FROM pm_presales_temp_auth ta WHERE 1=1
AND ta.lendInfoId = #{params.lendInfoId}
ORDER BY ta.createTime DESC
